import {
    useSignAndExecuteTransaction,
} from '@iota/dapp-kit';
import { useState } from 'react';
import { Transaction } from '@iota/iota-sdk/transactions';
import { FormRow, TextInput, TextArea, NumberInput } from './MoveFormsStyleHelper.tsx';
import { moveTarget, submitTx } from './MoveFormsTransactionHelper.tsx';

export function CreateDataTypeForm({ address }: { address: string }) {
  const { mutate } = useSignAndExecuteTransaction();
  const [digest, setDigest] = useState<string | null>(null);

  const [form, setForm] = useState({
    containerId: '',
    externalId: '',
    name: '',
    description: '',
    content: '',
    schemas: '',
    externalIndex: 0,
  });

  const submit = () => {
    const tx = new Transaction();

    tx.moveCall({
      target: moveTarget('create_data_type'),
      arguments: [
        tx.object(form.containerId),
        tx.pure.string(form.externalId),
        tx.pure.string(form.name),
        tx.pure.string(form.description),
        tx.pure.string(form.content),
        tx.pure.string(form.schemas),
        tx.pure.u128(form.externalIndex),
      ],
    });

    submitTx(mutate, tx, address, setDigest);
  };

  return (
    <FormSection title="Create Data Type">
      <FormRow label="Container ID">
        <TextInput
          placeholder="0x..."
          value={form.containerId}
          onChange={(value) => setForm(f => ({ ...f, containerId: value }))}
        />
      </FormRow>

      <FormRow label="External ID">
        <TextInput
          value={form.externalId}
          onChange={(value) => setForm(f => ({ ...f, externalId: value }))}
        />
      </FormRow>

      <FormRow label="Name">
        <TextInput
          value={form.name}
          onChange={(value) => setForm(f => ({ ...f, name: value }))}
        />
      </FormRow>

      <FormRow label="Description">
        <TextInput
          value={form.description}
          onChange={(value) => setForm(f => ({ ...f, description: value }))}
        />
      </FormRow>

      <FormRow label="Content">
        <TextArea
          rows={3}
          value={form.content}
          onChange={(value) => setForm(f => ({ ...f, content: value }))}
        />
      </FormRow>

      <FormRow label="Schemas">
        <TextArea
          rows={3}
          value={form.schemas}
          onChange={(value) => setForm(f => ({ ...f, schemas: value }))}
        />
      </FormRow>

      <FormRow label="External Index">
        <NumberInput
          value={form.externalIndex}
          onChange={(value) => setForm(f => ({ ...f, externalIndex: value }))}
        />
      </FormRow>

      <SubmitButton onClick={submit} label="Create Data Type" />

      {digest && (
        <div className="mt-2 text-muted small">
          Digest: {digest}
        </div>
      )}
    </FormSection>
  );
}
